# NL HMB.  Hoorn - Medemblik
#
let hm = path("d3.nl.hmb");

with detail = 4,
     railway = :second :museum
{
    # point.nl.Hoorn  nl.ZEH

    with link = "line.nl.HMB" {
        track(:ror, hm[:hoo + 329m, :hko - 0.49sw] << 1.5mo);
    }

    with link = "point.nl.Hoorn-Koepoortsweg", railway = :station {
        track(hm[:hko - 0.5sw, :hko + 0.5sw] << 1.5mo);
        marker(:left :de.hp :removed,
            hm[:hko] << 1.5mo << 0.5mt, hm[:hko] << 1.5mo >> 0.5mt
        );
        station(:right :removed,
            hm[:hko] >> 0.5mo >> 0.5mt + (1dt, 0dt),
            hbox(:left:top, "Hoorn Koepoortsweg"), "HMB: 0,3"
